s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')


def validate_input(event):
    """Validate and sanitize input data"""
    if not isinstance(event, dict):
        raise ValueError("Event must be a dictionary")
    
    required_fields = ['action', 'data']
    for field in required_fields:
        if field not in event:
            raise ValueError(f"Missing required field: {field}")
    
    allowed_actions = ['process', 'store', 'notify', 'queue']
    if event['action'] not in allowed_actions:
        raise ValueError(f"Invalid action. Allowed: {allowed_actions}")
    
    return True


def sanitize_string(value, max_length=256):
    """Sanitize string input to prevent injection attacks"""
    if not isinstance(value, str):
        return str(value)
    
    sanitized = value.strip()
    sanitized = sanitized[:max_length]
    
    dangerous_chars = ['<', '>', '"', "'", '&', ';', '|', '`', '$']
    for char in dangerous_chars:
        sanitized = sanitized.replace(char, '')
    
    return sanitized


def process_s3_operation(bucket_name, key, data=None, operation='get'):
    """Securely handle S3 operations"""
    try:
        bucket_name = sanitize_string(bucket_name, 63)
        key = sanitize_string(key, 1024)
        
        if operation == 'get':
            response = s3_client.get_object(
                Bucket=bucket_name,
                Key=key
            )
            return response['Body'].read().decode('utf-8')
        
        elif operation == 'put':
            if data is None:
                raise ValueError("Data required for put operation")
            
            s3_client.put_object(
                Bucket=bucket_name,
                Key=key,
                Body=json.dumps(data),
                ServerSideEncryption='AES256',
                ContentType='application/json'
            )
            return {'status': 'success', 'key': key}
        
        elif operation == 'delete':
            s3_client.delete_object(
                Bucket=bucket_name,
                Key=key
            )
            return {'status': 'deleted', 'key': key}
        
    except ClientError as e:
        logger.error(f"S3 operation failed: {str(e)}")
        raise


def process_dynamodb_operation(table_name, item_id, data=None, operation='get'):
    """Securely handle DynamoDB operations"""
    try:
        table_name = sanitize_string(table_name, 255)
        item_id = sanitize_string(item_id, 2048)
        
        table = dynamodb.Table(table_name)
        
        if operation == 'get':
            response = table.get_item(
                Key={'id': item_id}
            )
            return response.get('Item', {})
        
        elif operation == 'put':
            if data is None:
                raise ValueError("Data required for put operation")
            
            item = {
                'id': item_id,
                'timestamp': datetime.utcnow().isoformat(),
                **data
            }
            
            table.put_item(Item=item)
            return {'status': 'success', 'id': item_id}
        
        elif operation == 'update':
            if data is None:
                raise ValueError("Data required for update operation")
            
            update_expression = "SET "
            expression_values = {}
            
            for key, value in data.items():
                safe_key = sanitize_string(key, 255)
                update_expression += f"{safe_key} = :{safe_key}, "
                expression_values[f":{safe_key}"] = value
            
            update_expression = update_expression.rstrip(', ')
            
            response = table.update_item(
                Key={'id': item_id},
                UpdateExpression=update_expression,
                ExpressionAttributeValues=expression_values,
                ReturnValues='ALL_NEW'
            )
            return response.get('Attributes', {})
        
        elif operation == 'delete':
            table.delete_item(Key={'id': item_id})
            return {'status': 'deleted', 'id': item_id}
        
    except ClientError as e:
        logger.error(f"DynamoDB operation failed: {str(e)}")
        raise


def process_sns_operation(topic_arn, message, subject=None):
    """Securely publish to SNS"""
    try:
        topic_arn = sanitize_string(topic_arn, 1024)
        
        publish_params = {
            'TopicArn': topic_arn,
            'Message': json.dumps(message)
        }
        
        if subject:
            publish_params['Subject'] = sanitize_string(subject, 100)
        
        response = sns_client.publish(**publish_params)
        
        return {
            'status': 'published',
            'message_id': response['MessageId']
        }
        
    except ClientError as e:
        logger.error(f"SNS operation failed: {str(e)}")
        raise


def process_sqs_operation(queue_url, message=None, operation='send'):
    """Securely handle SQS operations"""
    try:
        queue_url = sanitize_string(queue_url, 1024)
        
        if operation == 'send':
            if message is None:
                raise ValueError("Message required for send operation")
            
            response = sqs_client.send_message(
                QueueUrl=queue_url,
                MessageBody=json.dumps(message)
            )
            
            return {
                'status': 'sent',
                'message_id': response['MessageId']
            }
        
        elif operation == 'receive':
            response = sqs_client.receive_message(
                QueueUrl=queue_url,
                MaxNumberOfMessages=10,
                WaitTimeSeconds=5
            )
            
            messages = response.get('Messages', [])
            return {'status': 'received', 'count': len(messages), 'messages': messages}
        
    except ClientError as e:
        logger.error(f"SQS operation failed: {str(e)}")
        raise


def lambda_handler(event, context):
    """
    Main Lambda handler function
    
    This function demonstrates usage of the shared IAM role across
    multiple AWS services (S3, DynamoDB, SNS, SQS)
    """
    try:
        logger.info(f"Received event: {json.dumps(event)}")
        
        validate_input(event)
        
        action = event['action']
        data = event['data']
        
        result = {}
        
        if action == 'process':
            bucket_name = os.environ.get('S3_BUCKET', 'microservices-data-bucket')
            table_name = os.environ.get('DYNAMODB_TABLE', 'microservices-data')
            
            s3_result = process_s3_operation(
                bucket_name=bucket_name,
                key=f"processed/{data.get('id', 'default')}.json",
                data=data,
                operation='put'
            )
            
            db_result = process_dynamodb_operation(
                table_name=table_name,
                item_id=data.get('id', 'default'),
                data=data,
                operation='put'
            )
            
            result = {
                's3': s3_result,
                'dynamodb': db_result
            }
        
        elif action == 'store':
            table_name = os.environ.get('DYNAMODB_TABLE', 'microservices-data')
            result = process_dynamodb_operation(
                table_name=table_name,
                item_id=data.get('id', 'default'),
                data=data,
                operation='put'
            )
        
        elif action == 'notify':
            topic_arn = os.environ.get('SNS_TOPIC_ARN', '')
            if not topic_arn:
                raise ValueError("SNS_TOPIC_ARN environment variable not set")
            
            result = process_sns_operation(
                topic_arn=topic_arn,
                message=data,
                subject=data.get('subject', 'Microservice Notification')
            )
        
        elif action == 'queue':
            queue_url = os.environ.get('SQS_QUEUE_URL', '')
            if not queue_url:
                raise ValueError("SQS_QUEUE_URL environment variable not set")
            
            result = process_sqs_operation(
                queue_url=queue_url,
                message=data,
                operation='send'
            )
        
        logger.info(f"Operation completed successfully: {json.dumps(result)}")
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Operation completed successfully',
                'action': action,
                'result': result,
                'timestamp': datetime.utcnow().isoformat()
            }),
            'headers': {
                'Content-Type': 'application/json',
                'X-Request-ID': context.request_id
            }
        }
        
    except ValueError as e:
        logger.error(f"Validation error: {str(e)}")
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'Validation error',
                'message': str(e)
            }),
            'headers': {'Content-Type': 'application/json'}
        }
        
    except ClientError as e:
        logger.error(f"AWS service error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Service error',
                'message': 'An error occurred while processing your request'
            }),
            'headers': {'Content-Type': 'application/json'}
        }
        
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal server error',
                'message': 'An unexpected error occurred'
            }),
            'headers': {'Content-Type': 'application/json'}
        }